import{_ as i,r as _,o as a,c,a as d,w as t,b as o,e}from"./app-d1f1b3a0.js";const A={},u=e("p",null,"笑笑出生的前一个周日（2022/8/7），我们一家人还去了平安大厦的高层吃了自助餐。随着预产期的临近，一家人的心情也略有些紧张，于是在8.9办理了住院。8.10早上7点多的时候，吴女士就破水了，让我俩感觉又意外又庆幸。在白天等待的时候，还给吴女士点了盒饭和悄悄送进了手机，但是后面据说因为躺着加上没有胃口，就也没吃得下多少东西。",-1),p=e("p",null,"在焦急等待到晚上后，我看着不断有宝宝从产房推出来，但迟迟没有见我们家崽崽的时候，心情就愈发焦急，虽然嘴上不断地说要冷静，但是内心的忧虑实在掩盖不住。",-1),r=e("p",null,"后来等到7点多的时候，还是只开了二指，医生基于担心宝宝缺氧，则建议我们尽早剖腹产。在签署手术同意书后差不多再过了1个小时，娃终于出来了！全身白白的，还紧闭着眼睛。",-1),B=e("p",null,"后来护士推着娃去打了疫苗，再过了半个小时吴女士才被推了出来，估计是因为麻药还没过的原因，她在病床上迷迷糊糊的。",-1),E=e("p",null,"等到了凌晨，给笑笑喂了几次奶，然后才匆匆睡去。第二天中午才稍微有点时间，还发了个朋友圈。",-1),v=e("p",null,[e("code",null,'<VideoPlayer src="https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/article/20220810%E7%AC%91%E7%AC%91%E5%87%BA%E7%94%9F%E6%9C%8B%E5%8F%8B%E5%9C%88.mp4" poster="https://pan.4a1801.life/d/Onedrive-4A1801/%E4%B8%AA%E4%BA%BA%E5%BB%BA%E7%AB%99/assets/article/20220810%E7%AC%91%E7%AC%91%E5%87%BA%E7%94%9F%E6%9C%8B%E5%8F%8B%E5%9C%88.jpg"/>')],-1),h=e("p",null,null,-1),C=e("p",null,"吴女士的月子中心特地找了一家离家很近的地方，离家3公里左右，还是那种面朝大海的“大别野”。环境还挺好的，月子餐也不错，我们在这里度过了初为人父人母的第一个月，一切都是挑战，在这里也学会了怎么给娃换尿布、洗澡。",-1),f=e("blockquote",null,[e("p",null,"其实这里的阿姨也不算太专业，尤其是单手抱娃洗澡的教法，让娃在后面一次体检中发现腿纹不对称。")],-1),m=e("p",null,"说来惭愧，带娃的主力主要是吴女士和笑笑外婆两位大将，笑爸偶尔出出力气。在吴女士休产假结束了以后，笑爸因为具有得天独厚的优势——公司离家走路10分钟的优势，偶尔中午还可以回家看看娃，不过也以打酱油为主就是了。",-1);function b(x,F){const n=_("Tabs");return a(),c("div",null,[d(n,{id:"0",data:[{id:"出生那一天"},{id:"月子中心"},{id:"带娃"}]},{title0:t(({value:s,isActive:l})=>[o("出生那一天")]),title1:t(({value:s,isActive:l})=>[o("月子中心")]),title2:t(({value:s,isActive:l})=>[o("带娃")]),tab0:t(({value:s,isActive:l})=>[u,p,r,B,E,v,h]),tab1:t(({value:s,isActive:l})=>[C,f]),tab2:t(({value:s,isActive:l})=>[m]),_:1})])}const k=i(A,[["render",b],["__file","笑笑出生回忆录.html.vue"]]);export{k as default};
